// Parse Typeform webhook payload
const webhookData = $input.first().json;
const formResponse = webhookData.form_response || webhookData;

// Extract answers
const answers = {};
if (formResponse.answers) {
  formResponse.answers.forEach(answer => {
    const fieldRef = answer.field?.ref || answer.field?.id || '';
    if (answer.type === 'email') answers.email = answer.email || '';
    else if (answer.type === 'text') answers[fieldRef] = answer.text || '';
    else if (answer.type === 'long_text') answers[fieldRef] = answer.text || '';
    else if (answer.type === 'choice') answers[fieldRef] = answer.choice?.label || '';
    else if (answer.type === 'choices') answers[fieldRef] = answer.choices?.labels || [];
    else if (answer.type === 'number') answers[fieldRef] = parseInt(answer.number || 0);
  });
}

const formData = {
  business_name: answers.business_name || answers['business-name'] || '',
  email: answers.email || answers.Email || '',
  manual_processes: answers.manual_processes || answers['manual-processes'] || '',
  current_automation: Array.isArray(answers.current_automation || answers['current-automation']) ? answers.current_automation || answers['current-automation'] : [],
  team_size: parseInt(answers.team_size || answers['team-size'] || 0),
  monthly_revenue: answers.monthly_revenue || answers['monthly-revenue'] || '',
  top_priority: answers.top_priority || answers['top-priority'] || '',
  budget: answers.budget || answers.Budget || '',
  form_id: webhookData.form_id || '',
  submitted_at: formResponse.submitted_at || new Date().toISOString()
};

// Calculate readiness score
let score = 0;

// Manual Processes (25 points)
const manualProcessScores = {
  '0-5 (minimal)': 5,
  '6-15 (moderate)': 15,
  '16-30 (significant)': 20,
  '31+ (overwhelming)': 25
};
score += manualProcessScores[formData.manual_processes] || 0;

// Current Automation (30 points)
const automationCount = formData.current_automation.length;
score += Math.min(automationCount * 10, 30);

// Team Size (20 points)
score += Math.min(Math.floor(formData.team_size / 10) * 20, 20);

// Revenue (25 points)
const revenueScores = {
  'Under $10k': 5,
  '$10k-$50k': 10,
  '$50k-$100k': 15,
  '$100k-$500k': 20,
  '$500k+': 25
};
score += revenueScores[formData.monthly_revenue] || 0;

// Priority Clarity (10 bonus)
if (formData.top_priority && formData.top_priority.length > 50) score += 10;

// Budget Awareness (40 bonus, capped at 100)
const budgetScores = {
  "Haven't thought about it yet": 0,
  'Under $5,000': 10,
  '$5,000-$10,000': 20,
  '$10,000-$25,000': 30,
  '$25,000+': 40
};
score = Math.min(score + (budgetScores[formData.budget] || 0), 100);

// Determine readiness level
let readinessLevel = 'Not Ready';
if (score >= 81) readinessLevel = 'Highly Ready';
else if (score >= 61) readinessLevel = 'Ready';
else if (score >= 31) readinessLevel = 'Getting Ready';

return [{
  json: {
    success: true,
    formData: formData,
    readinessScore: score,
    readinessLevel: readinessLevel
  }
}];

// Generate HTML for PDF scorecard
const score = $('Parse & Calculate Score').item.json.readinessScore;
const level = $('Parse & Calculate Score').item.json.readinessLevel;
const businessName = $('Parse & Calculate Score').item.json.formData.business_name;
const aiAnalysis = $('AI Analysis (OpenAI)').item.json.choices?.[0]?.message?.content || '';

const html = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: 'Outfit', Arial, sans-serif; padding: 40px; background: #110d28; color: #ffffff; }
    .header { text-align: center; margin-bottom: 40px; }
    .score-circle { width: 200px; height: 200px; border-radius: 50%; border: 8px solid #fe3d51; display: flex; align-items: center; justify-content: center; margin: 0 auto; background: linear-gradient(135deg, #fe3d51 0%, #bf5700 100%); }
    .score-number { font-size: 72px; font-weight: bold; }
    .level { font-size: 24px; margin-top: 20px; color: #5ffbfd; }
    .section { margin: 30px 0; padding: 20px; background: #1a1635; border-radius: 10px; }
    .opportunities { margin-top: 20px; }
    .opportunity { padding: 15px; margin: 10px 0; background: rgba(95, 251, 253, 0.1); border-left: 4px solid #5ffbfd; }
  </style>
</head>
<body>
  <div class="header">
    <h1>Automation Readiness Scorecard</h1>
    <h2>${businessName}</h2>
  </div>
  <div class="score-circle">
    <div class="score-number">${score}</div>
  </div>
  <div class="level">${level}</div>
  <div class="section">
    <h3>Top 3 Automation Opportunities</h3>
    <div class="opportunities">${aiAnalysis}</div>
  </div>
  <div class="section">
    <h3>Next Steps</h3>
    <p>Based on your score of ${score}/100, we recommend:</p>
    <ul>
      ${level === 'Highly Ready' || level === 'Ready' ? '<li>Book a FREE consultation to discuss custom automation solutions</li>' : ''}
      ${level === 'Getting Ready' ? '<li>Start with simple automation tools</li>' : ''}
      ${level === 'Not Ready' ? '<li>Focus on business basics first</li>' : ''}
    </ul>
  </div>
</body>
</html>
`;

return [{
  json: {
    html: html,
    score: score,
    level: level
  }
}];

